svg.metadata:

# Entity-Relationship Definition (auto-generated)

entities:
  backend_category:
    comment: 后台类目
    columns:
      - { name: category_id, type: BIGINT, pk: true, comment: "类目ID" }
      - { name: parent_id, type: BIGINT, fk: backend_category.category_id, nullable: true, comment: "父类目ID" }
      - { name: category_name, type: VARCHAR(100), not_null: true, comment: "类目名称" }
      - { name: level, type: TINYINT, comment: "层级深度" }
      - { name: sort_order, type: INT, default: 0 }
      - { name: status, type: TINYINT, default: 1 }
    indexes:
      - { columns: [parent_id], type: index }
  frontend_category:
    comment: 前台类目
    columns:
      - { name: category_id, type: BIGINT, pk: true, comment: "前台类目ID" }
      - { name: parent_id, type: BIGINT, nullable: true, comment: "父类目ID" }
      - { name: category_name, type: VARCHAR(100), not_null: true }
      - { name: icon_url, type: VARCHAR(500) }
      - { name: sort_order, type: INT, default: 0 }
      - { name: status, type: TINYINT, default: 1 }
  category_mapping:
    comment: 类目映射
    columns:
      - { name: id, type: BIGINT, pk: true }
      - { name: frontend_id, type: BIGINT, fk: frontend_category.category_id }
      - { name: backend_id, type: BIGINT, fk: backend_category.category_id }
      - { name: sort_order, type: INT, default: 0 }
    indexes:
      - { columns: [frontend_id, backend_id], type: unique }
  attribute_option:
    comment: 属性选项
    columns:
      - { name: option_id, type: BIGINT, pk: true }
      - { name: attribute_id, type: BIGINT, fk: attribute_def.attribute_id }
      - { name: option_value, type: VARCHAR(200), not_null: true, comment: "如256GB、深空黑" }
      - { name: sort_order, type: INT, default: 0 }
    indexes:
      - { columns: [attribute_id], type: index }
  category_attribute:
    comment: 类目属性模板（旧版，仅表达类目级默认配置）
    columns:
      - { name: id, type: BIGINT, pk: true }
      - { name: category_id, type: BIGINT, fk: backend_category.category_id }
      - { name: attribute_id, type: BIGINT, fk: attribute_def.attribute_id }
      - { name: attribute_type, type: ENUM, comment: "key=关键属性 sale=销售属性 non_key=非关键属性" }
      - { name: is_required, type: BOOLEAN, default: False }
      - { name: sort_order, type: INT, default: 0 }
      - { name: status, type: TINYINT, default: 1, comment: "启用状态" }
    indexes:
      - { columns: [category_id, attribute_id], type: unique }
      - { columns: [category_id, sort_order], type: index }
  brand:
    comment: 品牌
    columns:
      - { name: brand_id, type: BIGINT, pk: true }
      - { name: brand_name, type: VARCHAR(100), not_null: true }
      - { name: brand_name_en, type: VARCHAR(100) }
      - { name: logo_url, type: VARCHAR(500) }
      - { name: status, type: TINYINT, default: 1 }
  category_brand:
    comment: 类目品牌
    columns:
      - { name: id, type: BIGINT, pk: true }
      - { name: category_id, type: BIGINT, fk: backend_category.category_id }
      - { name: brand_id, type: BIGINT, fk: brand.brand_id }
      - { name: sort_order, type: INT, default: 0 }
    indexes:
      - { columns: [category_id, brand_id], type: unique }
  attribute_group:
    comment: 属性分组
    columns:
      - { name: group_id, type: BIGINT, pk: true }
      - { name: category_id, type: BIGINT, fk: backend_category.category_id }
      - { name: group_name, type: VARCHAR(50), not_null: true }
      - { name: sort_order, type: INT, default: 0 }
    indexes:
      - { columns: [category_id], type: index }
  attribute_def:
    comment: 属性定义
    columns:
      - { name: attribute_id, type: BIGINT, pk: true }
      - { name: group_id, type: BIGINT, fk: attribute_group.group_id }
      - { name: attribute_name, type: VARCHAR(50), not_null: true, comment: "如屏幕尺寸、存储容量" }
      - { name: attribute_type, type: ENUM, comment: "属性值类型" }
      - { name: input_type, type: ENUM, comment: "text/select/multi_select/number" }
      - { name: is_required, type: BOOLEAN, default: False }
      - { name: sort_order, type: INT, default: 0 }
    indexes:
      - { columns: [group_id], type: index }
  spu:
    comment: 标准产品单元
    columns:
      - { name: spu_id, type: BIGINT, pk: true }
      - { name: category_id, type: BIGINT, fk: backend_category.category_id }
      - { name: series_id, type: BIGINT, fk: series.series_id }
      - { name: spu_name, type: VARCHAR(200), not_null: true, comment: "如iPhone 15 Pro Max" }
      - { name: model, type: VARCHAR(100), comment: "如A3106" }
      - { name: description, type: TEXT }
      - { name: status, type: TINYINT, default: 1 }
    indexes:
      - { columns: [category_id], type: index }
      - { columns: [series_id], type: index }
  spu_attribute_value:
    comment: SPU属性值
    columns:
      - { name: id, type: BIGINT, pk: true }
      - { name: spu_id, type: BIGINT, fk: spu.spu_id }
      - { name: attribute_id, type: BIGINT, fk: attribute_def.attribute_id }
      - { name: attribute_value, type: VARCHAR(500), not_null: true }
      - { name: option_id, type: BIGINT, fk: attribute_option.option_id }
    indexes:
      - { columns: [spu_id, attribute_id], type: unique }
  spu_image:
    comment: SPU图片
    columns:
      - { name: image_id, type: BIGINT, pk: true }
      - { name: spu_id, type: BIGINT, fk: spu.spu_id }
      - { name: image_url, type: VARCHAR(500), not_null: true }
      - { name: image_type, type: ENUM, comment: "main/detail/video/certificate" }
      - { name: sort_order, type: INT, default: 0 }
    indexes:
      - { columns: [spu_id], type: index }
  standard_sku:
    comment: 标品SKU
    columns:
      - { name: standard_sku_id, type: BIGINT, pk: true }
      - { name: spu_id, type: BIGINT, fk: spu.spu_id }
      - { name: sku_name, type: VARCHAR(200), not_null: true, comment: "如iPhone 15 Pro Max 深空黑 256GB" }
      - { name: barcode, type: VARCHAR(50), comment: "国际条码EAN/UPC" }
      - { name: market_price, type: DECIMAL(12,2), comment: "官方参考价" }
      - { name: status, type: TINYINT, default: 1 }
    indexes:
      - { columns: [spu_id], type: index }
  standard_sku_attribute:
    comment: SKU属性
    columns:
      - { name: id, type: BIGINT, pk: true }
      - { name: standard_sku_id, type: BIGINT, fk: standard_sku.standard_sku_id }
      - { name: attribute_id, type: BIGINT, fk: attribute_def.attribute_id }
      - { name: attribute_value, type: VARCHAR(500), not_null: true }
    indexes:
      - { columns: [standard_sku_id, attribute_id], type: unique }
  standard_sku_image:
    comment: SKU图片
    columns:
      - { name: image_id, type: BIGINT, pk: true }
      - { name: standard_sku_id, type: BIGINT, fk: standard_sku.standard_sku_id }
      - { name: image_url, type: VARCHAR(500), not_null: true }
      - { name: image_type, type: ENUM, comment: "main/detail/swatch(色卡)" }
      - { name: sort_order, type: INT, default: 0 }
    indexes:
      - { columns: [standard_sku_id], type: index }
  warehouse:
    comment: 仓库
    columns:
      - { name: warehouse_id, type: BIGINT, pk: true }
      - { name: warehouse_name, type: VARCHAR(100), not_null: true }
      - { name: address, type: VARCHAR(500) }
      - { name: type, type: ENUM, comment: "warehouse/store" }
      - { name: status, type: TINYINT, default: 1 }
  used_item:
    comment: 二手商品（一物一码）
    columns:
      - { name: item_id, type: BIGINT, pk: true }
      - { name: standard_sku_id, type: BIGINT, fk: standard_sku.standard_sku_id, comment: "关联到具体规格" }
      - { name: warehouse_id, type: BIGINT, fk: warehouse.warehouse_id }
      - { name: item_code, type: VARCHAR(50), unique: true, comment: "内部条码号" }
      - { name: title, type: VARCHAR(200) }
      - { name: grade, type: ENUM, not_null: true, comment: "成色等级S/A/B/C/D" }
      - { name: purchase_price, type: DECIMAL(12,2), comment: "采购/回收成本" }
      - { name: base_price, type: DECIMAL(12,2), comment: "基准售价" }
      - { name: source, type: VARCHAR(100), comment: "来源: 回收/寄卖/采购" }
      - { name: serial_number, type: VARCHAR(100), comment: "序列号/IMEI" }
      - { name: is_authenticated, type: BOOLEAN, default: False }
      - { name: authenticator, type: VARCHAR(100), comment: "鉴定方" }
      - { name: certificate_url, type: VARCHAR(500), comment: "鉴定证书" }
      - { name: stock_status, type: ENUM, comment: "in_stock/locked/sold/returned" }
      - { name: images, type: JSON, comment: "实拍图URL数组" }
    indexes:
      - { columns: [standard_sku_id], type: index }
      - { columns: [stock_status], type: index }
      - { columns: [grade], type: index }
  item_condition:
    comment: 质检明细
    columns:
      - { name: condition_id, type: BIGINT, pk: true }
      - { name: item_id, type: BIGINT, fk: used_item.item_id }
      - { name: check_type, type: ENUM, not_null: true, comment: "appearance/function" }
      - { name: check_item, type: VARCHAR(100), not_null: true, comment: "如屏幕、边框、电池健康度" }
      - { name: result, type: VARCHAR(200), not_null: true, comment: "如轻微划痕、正常、85%" }
      - { name: defect_images, type: JSON, comment: "瑕疵实拍图" }
      - { name: sort_order, type: INT, default: 0 }
    indexes:
      - { columns: [item_id], type: index }
  listing:
    comment: 渠道商品
    columns:
      - { name: listing_id, type: BIGINT, pk: true }
      - { name: item_id, type: BIGINT, fk: used_item.item_id }
      - { name: channel_id, type: BIGINT, fk: channel.channel_id }
      - { name: listing_price, type: DECIMAL(12,2), not_null: true, comment: "该渠道售价" }
      - { name: promotion_price, type: DECIMAL(12,2), comment: "活动价" }
      - { name: listing_status, type: ENUM, comment: "listed/unlisted/presale" }
      - { name: priority, type: INT, default: 0, comment: "渠道优先级" }
      - { name: listed_at, type: DATETIME }
    indexes:
      - { columns: [item_id, channel_id], type: unique }
      - { columns: [listing_status], type: index }
  channel:
    comment: 渠道
    columns:
      - { name: channel_id, type: BIGINT, pk: true }
      - { name: channel_name, type: VARCHAR(100), not_null: true, comment: "如自营APP、门店、得物" }
      - { name: channel_type, type: ENUM, comment: "online/offline/third_party" }
      - { name: commission_rate, type: DECIMAL(5,2) }
      - { name: status, type: TINYINT, default: 1 }
  series:
    comment: 产品系列
    columns:
      - { name: series_id, type: BIGINT, pk: true, comment: "系列ID" }
      - { name: brand_id, type: BIGINT, fk: brand.brand_id, comment: "所属品牌" }
      - { name: series_name, type: VARCHAR(100), not_null: true, comment: "系列名称" }
      - { name: series_name_en, type: VARCHAR(100), comment: "系列英文名" }
      - { name: description, type: TEXT, comment: "系列说明" }
      - { name: status, type: TINYINT, default: 1 }
    indexes:
      - { columns: [brand_id], type: index }
      - { columns: [brand_id, series_name], type: unique }
  series_category:
    comment: 系列类目映射
    columns:
      - { name: id, type: BIGINT, pk: true }
      - { name: series_id, type: BIGINT, fk: series.series_id }
      - { name: category_id, type: BIGINT, fk: backend_category.category_id }
      - { name: sort_order, type: INT, default: 0 }
    indexes:
      - { columns: [series_id, category_id], type: unique }
  attribute_scope_config:
    comment: 属性作用域配置
    columns:
      - { name: id, type: BIGINT, pk: true, comment: "作用域配置ID" }
      - { name: category_id, type: BIGINT, fk: backend_category.category_id, comment: "后台类目ID" }
      - { name: scope_type, type: ENUM, not_null: true, comment: "CATEGORY/CATEGORY_BRAND/CATEGORY_SERIES" }
      - { name: brand_id, type: BIGINT, fk: brand.brand_id, nullable: true, comment: "品牌ID，scope_type=CATEGORY_BRAND时必填" }
      - { name: series_id, type: BIGINT, fk: series.series_id, nullable: true, comment: "系列ID，scope_type=CATEGORY_SERIES时必填" }
      - { name: attribute_id, type: BIGINT, fk: attribute_def.attribute_id, comment: "属性ID" }
      - { name: attribute_type, type: ENUM, comment: "key/sale/non_key" }
      - { name: is_required, type: BOOLEAN, default: False, comment: "是否必填" }
      - { name: sort_order, type: INT, default: 0, comment: "展示排序" }
      - { name: status, type: TINYINT, default: 1, comment: "启用状态" }
    indexes:
      - { columns: [category_id, scope_type, brand_id, series_id, attribute_id], type: unique }
      - { columns: [category_id, series_id, attribute_id, status], type: index }
      - { columns: [category_id, brand_id, attribute_id, status], type: index }
      - { columns: [category_id, attribute_id, status], type: index }
  attribute_option_scope_config:
    comment: 属性选项作用域配置
    columns:
      - { name: id, type: BIGINT, pk: true, comment: "选项作用域配置ID" }
      - { name: category_id, type: BIGINT, fk: backend_category.category_id, comment: "后台类目ID" }
      - { name: scope_type, type: ENUM, not_null: true, comment: "CATEGORY/CATEGORY_BRAND/CATEGORY_SERIES" }
      - { name: brand_id, type: BIGINT, fk: brand.brand_id, nullable: true, comment: "品牌ID，scope_type=CATEGORY_BRAND时必填" }
      - { name: series_id, type: BIGINT, fk: series.series_id, nullable: true, comment: "系列ID，scope_type=CATEGORY_SERIES时必填" }
      - { name: attribute_id, type: BIGINT, fk: attribute_def.attribute_id, comment: "属性ID" }
      - { name: option_id, type: BIGINT, fk: attribute_option.option_id, comment: "允许的属性选项ID" }
      - { name: sort_order, type: INT, default: 0, comment: "选项排序" }
      - { name: status, type: TINYINT, default: 1, comment: "启用状态" }
    indexes:
      - { columns: [category_id, scope_type, brand_id, series_id, attribute_id, option_id], type: unique }
      - { columns: [category_id, series_id, attribute_id, status], type: index }
      - { columns: [category_id, brand_id, attribute_id, status], type: index }
      - { columns: [category_id, attribute_id, status], type: index }
      - { columns: [attribute_id, option_id], type: index }

relations:
  - { from: series.brand_id, to: brand.brand_id, type: "N:1", comment: "多个系列属于同一品牌" }
  - { from: spu.category_id, to: backend_category.category_id, type: "N:1", comment: "多个标品属于同一类目" }
  - { from: spu.series_id, to: series.series_id, type: "N:1", comment: "多个标品属于同一产品系列" }
  - { from: category_brand.category_id, to: backend_category.category_id, type: "N:1" }
  - { from: category_brand.brand_id, to: brand.brand_id, type: "N:1" }
  - { from: series_category.series_id, to: series.series_id, type: "N:1", comment: "系列可映射多个后台类目" }
  - { from: series_category.category_id, to: backend_category.category_id, type: "N:1", comment: "一个后台类目可关联多个产品系列" }
  - { from: category_mapping.frontend_id, to: frontend_category.category_id, type: "N:1" }
  - { from: category_mapping.backend_id, to: backend_category.category_id, type: "N:1" }
  - { from: attribute_group.category_id, to: backend_category.category_id, type: "N:1" }
  - { from: attribute_def.group_id, to: attribute_group.group_id, type: "N:1" }
  - { from: attribute_option.attribute_id, to: attribute_def.attribute_id, type: "N:1" }
  - { from: category_attribute.category_id, to: backend_category.category_id, type: "N:1" }
  - { from: category_attribute.attribute_id, to: attribute_def.attribute_id, type: "N:1" }
  - { from: attribute_scope_config.category_id, to: backend_category.category_id, type: "N:1", comment: "属性作用域配置绑定后台类目" }
  - { from: attribute_scope_config.brand_id, to: brand.brand_id, type: "N:1", comment: "品牌维度属性覆盖" }
  - { from: attribute_scope_config.series_id, to: series.series_id, type: "N:1", comment: "系列维度属性覆盖" }
  - { from: attribute_scope_config.attribute_id, to: attribute_def.attribute_id, type: "N:1", comment: "作用域配置命中具体属性" }
  - { from: attribute_option_scope_config.category_id, to: backend_category.category_id, type: "N:1", comment: "选项作用域配置绑定后台类目" }
  - { from: attribute_option_scope_config.brand_id, to: brand.brand_id, type: "N:1", comment: "品牌维度选项覆盖" }
  - { from: attribute_option_scope_config.series_id, to: series.series_id, type: "N:1", comment: "系列维度选项覆盖" }
  - { from: attribute_option_scope_config.attribute_id, to: attribute_def.attribute_id, type: "N:1", comment: "选项作用域配置命中属性" }
  - { from: attribute_option_scope_config.option_id, to: attribute_option.option_id, type: "N:1", comment: "选项作用域配置约束可用选项" }
  - { from: spu_attribute_value.spu_id, to: spu.spu_id, type: "N:1" }
  - { from: spu_attribute_value.attribute_id, to: attribute_def.attribute_id, type: "N:1" }
  - { from: spu_image.spu_id, to: spu.spu_id, type: "N:1" }
  - { from: standard_sku.spu_id, to: spu.spu_id, type: "N:1", comment: "一个标品对应多个标品SKU" }
  - { from: standard_sku_attribute.standard_sku_id, to: standard_sku.standard_sku_id, type: "N:1" }
  - { from: standard_sku_attribute.attribute_id, to: attribute_def.attribute_id, type: "N:1" }
  - { from: standard_sku_image.standard_sku_id, to: standard_sku.standard_sku_id, type: "N:1" }
  - { from: used_item.standard_sku_id, to: standard_sku.standard_sku_id, type: "N:1", comment: "一个标品SKU对应多件二手实物" }
  - { from: used_item.warehouse_id, to: warehouse.warehouse_id, type: "N:1" }
  - { from: item_condition.item_id, to: used_item.item_id, type: "N:1" }
  - { from: listing.item_id, to: used_item.item_id, type: "N:1", comment: "一件二手商品可挂多个渠道" }
  - { from: listing.channel_id, to: channel.channel_id, type: "N:1" }
